## Step 3: Refactor `apps/web/src/hooks/useTheme.ts`

This is the most complex change. The file must:

1. Import `ThemeName`, `ConcreteThemeName`, `BUILT_IN_THEMES` from `@t3tools/shared/theme`
2. Change the storage key to `"t3code:custom-theme"` and migrate old values on read
3. Update `applyTheme()` to set both the `.dark` class AND inject CSS custom properties via `style.setProperty`
4. Keep the existing `useSyncExternalStore` external store pattern exactly (no React context)
5. Remain StrictMode safe

**Key design points:**

The migration function runs inside `getStored()`. It reads both the old key and new key, migrating on first read if only the old value is present:

```typescript
const OLD_STORAGE_KEY = "t3code:theme";
const STORAGE_KEY = "t3code:custom-theme";

function migrateTheme(): ThemeName {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight" || raw === "system") {
    return raw;
  }
  // Migrate from old key
  const legacy = localStorage.getItem(OLD_STORAGE_KEY);
  if (legacy === "dark") {
    localStorage.setItem(STORAGE_KEY, "t3-dark");
    return "t3-dark";
  }
  if (legacy === "light") {
    localStorage.setItem(STORAGE_KEY, "t3-light");
    return "t3-light";
  }
  // "system" or unrecognized both become "system"
  return "system";
}
```

The `applyTheme` function now also injects CSS properties. Note the `noUncheckedIndexedAccess` concern: `BUILT_IN_THEMES[concreteTheme]` returns `ThemeDefinition | undefined`. We must handle this with a non-null assertion or an explicit guard. The recommended approach is an explicit guard (more robust):

```typescript
function applyTheme(theme: ThemeName, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const resolvedName = theme === "system"
    ? (getSystemDark() ? "t3-dark" : "t3-light")
    : theme;
  const isDark = theme === "system" ? getSystemDark() : (BUILT_IN_THEMES[resolvedName]?.isDark ?? false);
  document.documentElement.classList.toggle("dark", isDark);

  // Inject CSS custom properties from the resolved theme
  const def = BUILT_IN_THEMES[resolvedName];
  if (def !== undefined) {
    const el = document.documentElement;
    el.style.setProperty("--background", def.colors.background);
    el.style.setProperty("--foreground", def.colors.foreground);
    el.style.setProperty("--primary", def.colors.accent);
    el.style.setProperty("--primary-foreground", def.colors.accentForeground);
    el.style.setProperty("--ring", def.colors.accent);
    el.style.setProperty("--theme-sidebar", def.colors.sidebar);
    el.style.setProperty("--theme-editor", def.colors.editor);
    el.style.setProperty("--theme-terminal", def.colors.terminal);
    el.style.setProperty("--theme-status-bar", def.colors.statusBar);
  }

  if (suppressTransitions) {
    document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}
```

The `resolvedTheme` returned from `useTheme()` changes type: it should remain `"light" | "dark"` for backward compatibility (since `DiffWorkerPoolProvider` passes it to `resolveDiffThemeName` which expects `"light" | "dark"`). Derive it as:

```typescript
const resolvedTheme: "light" | "dark" =
  theme === "system"
    ? (snapshot.systemDark ? "dark" : "light")
    : (BUILT_IN_THEMES[theme]?.isDark ? "dark" : "light");
```

The `setTheme` callback signature becomes `(next: ThemeName) => void`.

The snapshot type and `getSnapshot` function update to use `ThemeName` instead of the old `Theme`:

```typescript
type ThemeSnapshot = {
  theme: ThemeName;
  systemDark: boolean;
};
```

The `subscribe` function's storage event handler must check the new key:

```typescript
const handleStorage = (e: StorageEvent) => {
  if (e.key === STORAGE_KEY || e.key === OLD_STORAGE_KEY) {
    applyTheme(migrateTheme(), true);
    emitChange();
  }
};
```

Return type from `useTheme` becomes `{ theme: ThemeName; setTheme: (next: ThemeName) => void; resolvedTheme: "light" | "dark" }`.

