import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  type ConcreteThemeName,
  type ThemeName,
} from "@t3tools/shared/theme";

const OLD_STORAGE_KEY = "t3code:theme";
const STORAGE_KEY = "t3code:custom-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: { theme: ThemeName; systemDark: boolean } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function migrateTheme(): ThemeName {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight" || raw === "system") {
    return raw;
  }
  // Migrate from old key
  const legacy = localStorage.getItem(OLD_STORAGE_KEY);
  if (legacy === "dark") {
    localStorage.setItem(STORAGE_KEY, "t3-dark");
    return "t3-dark";
  }
  if (legacy === "light") {
    localStorage.setItem(STORAGE_KEY, "t3-light");
    return "t3-light";
  }
  // "system" or unrecognized → "system"
  return "system";
}

function resolveConcreteTheme(theme: ThemeName): ConcreteThemeName {
  if (theme === "system") {
    return getSystemDark() ? "t3-dark" : "t3-light";
  }
  return theme;
}

function applyThemeCssVars(concreteTheme: ConcreteThemeName): void {
  const def = BUILT_IN_THEMES[concreteTheme] as (typeof BUILT_IN_THEMES)[ConcreteThemeName] | undefined;
  if (def === undefined) return;
  const el = document.documentElement;
  const { colors } = def;
  el.style.setProperty("--background", colors.background);
  el.style.setProperty("--foreground", colors.foreground);
  el.style.setProperty("--primary", colors.accent);
  el.style.setProperty("--primary-foreground", colors.accentForeground);
  el.style.setProperty("--ring", colors.accent);
  el.style.setProperty("--theme-sidebar", colors.sidebar);
  el.style.setProperty("--theme-editor", colors.editor);
  el.style.setProperty("--theme-terminal", colors.terminal);
  el.style.setProperty("--theme-status-bar", colors.statusBar);
}

function applyTheme(theme: ThemeName, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const concrete = resolveConcreteTheme(theme);
  const def = BUILT_IN_THEMES[concrete] as (typeof BUILT_IN_THEMES)[ConcreteThemeName] | undefined;
  const isDark = def?.isDark ?? false;
  document.documentElement.classList.toggle("dark", isDark);
  applyThemeCssVars(concrete);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(migrateTheme());

function getSnapshot(): { theme: ThemeName; systemDark: boolean } {
  const theme = migrateTheme();
  const systemDark = theme === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.theme === theme &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (migrateTheme() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY || e.key === OLD_STORAGE_KEY) {
      applyTheme(migrateTheme(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;

  const resolvedTheme: "light" | "dark" =
    theme === "system"
      ? (snapshot.systemDark ? "dark" : "light")
      : ((BUILT_IN_THEMES[theme] as (typeof BUILT_IN_THEMES)[ConcreteThemeName] | undefined)?.isDark
          ? "dark"
          : "light");

  const setTheme = useCallback((next: ThemeName) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme } as const;
}

