import { type ReactNode } from "react";
import { useTheme } from "~/hooks/useTheme";

interface ThemeProviderProps {
  children?: ReactNode;
}

/**
 * Mounts the theme subscription at the root of the React tree, ensuring the
 * internal useEffect inside useTheme fires before any child renders that depend
 * on CSS custom properties. Idempotent: the underlying applyTheme function is
 * safe to call multiple times with the same value (StrictMode safe).
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Subscribing here ensures CSS vars and .dark class stay in sync with
  // React's lifecycle (StrictMode double-invoke safe).
  useTheme();
  return <>{children}</>;
}

