function ThemePreviewSwatch({ background, sidebar, accent, statusBar }: SwatchProps) {
  return (
    <div
      className="relative h-10 w-16 shrink-0 overflow-hidden rounded-md border border-black/10 dark:border-white/10"
      style={{ background }}
    >
      {/* Sidebar strip (left) */}
      <div className="absolute inset-y-0 left-0 w-3" style={{ background: sidebar }} />
      {/* Status bar strip (bottom) */}
      <div className="absolute inset-x-0 bottom-0 h-1.5" style={{ background: statusBar }} />
      {/* Accent dot (top-right) */}
      <div
        className="absolute right-1.5 top-1.5 h-2 w-2 rounded-full"
        style={{ background: accent }}
      />
    </div>
  );
}

function SystemThemePreviewSwatch() {
  // Use hard-coded colors so the preview is correct regardless of active theme
  const light = BUILT_IN_THEMES["t3-light"].colors;
  const dark = BUILT_IN_THEMES["t3-dark"].colors;
  return (
    <div className="relative h-10 w-16 shrink-0 overflow-hidden rounded-md border border-black/10 dark:border-white/10">
      {/* Light half */}
      <div
        className="absolute inset-y-0 left-0 right-1/2"
        style={{ background: light.background }}
      />
      {/* Dark half */}
      <div
        className="absolute inset-y-0 left-1/2 right-0"
        style={{ background: dark.background }}
      />
      {/* Subtle diagonal divider */}
      <div
        className="absolute inset-0"
        style={{
          background:
            "linear-gradient(to right, transparent 48%, rgba(0,0,0,0.12) 50%, transparent 52%)",
        }}
      />
    </div>
  );
}

interface ThemeOptionProps {
  name: ThemeName;
  label: string;
  description: string;
  selected: boolean;
  onSelect: (name: ThemeName) => void;
  swatch: React.ReactNode;
}

function ThemeOption({ name, label, description, selected, onSelect, swatch }: ThemeOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={() => onSelect(name)}
      className={cn(
        "flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
    >
      {swatch}
      <span className="flex min-w-0 flex-1 flex-col">
        <span className="text-sm font-medium">{label}</span>
        <span className="text-xs">{description}</span>
      </span>
      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

/**
 * Visual theme selector with preview swatches for each built-in theme plus
 * the "system" option. Preview boxes use inline styles with hard-coded color
 * values (not CSS vars) so swatches display correctly regardless of which
 * theme is currently active.
 */
export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      {CONCRETE_THEME_NAMES.map((name: ConcreteThemeName) => {
        const def = BUILT_IN_THEMES[name];
        return (
          <ThemeOption
            key={name}
            name={name}
            label={def.label}
            description={def.description}
            selected={theme === name}
            onSelect={setTheme}
            swatch={
              <ThemePreviewSwatch
                background={def.colors.background}
                sidebar={def.colors.sidebar}
                accent={def.colors.accent}
                statusBar={def.colors.statusBar}
              />
            }
          />
        );
      })}

      <ThemeOption
        name="system"
        label="System"
        description="Match your OS appearance setting."
        selected={theme === "system"}
        onSelect={setTheme}
        swatch={<SystemThemePreviewSwatch />}
      />
    </div>
  );
}

